proof fn phi_1_roundtrip_external_body_trusted<C: SecureSpecCombinator>(
    c: &C,
    v: C::Type,
)
    requires
        c.requires(),
        c.wf(v),
    ensures
        c.spec_parse(c.spec_serialize(v)) == Some((c.spec_serialize(v).len() as int, v)),
{
    c.theorem_serialize_parse_roundtrip(v);
}

proof fn phi_2_serialize_injective_from_external<C: SecureSpecCombinator>(
    c: &C,
    v1: C::Type,
    v2: C::Type,
)
    requires
        c.requires(),
        c.wf(v1),
        c.wf(v2),
        c.spec_serialize(v1) == c.spec_serialize(v2),
    ensures
        v1 == v2,
{
    c.theorem_serialize_parse_roundtrip(v1);
    c.theorem_serialize_parse_roundtrip(v2);
}

